def seed_database():
    """Insert all seed ingredients into the database."""
    count = 0
    for code, name, status, category, explanation, source in SEED_INGREDIENTS:
        try:
            db.add_ingredient(
                code=code,
                name=name,
                status=status,
                category=category,
                explanation=explanation,
                source=source,
                confidence=1.0,
                ai_generated=False,
            )
            count += 1
        except Exception as e:
            print(f"Error adding {name}: {e}")

    print(f"✅ Seeded {count} ingredients into database")
    return count


if __name__ == "__main__":
    seed_database()
